/// <summary>
/// Helper class providing common utility methods for customer-related operations.
/// </summary>
public class CustSampleHelper
{
}

Method.Source:
/// <summary>
/// Retrieves the customer name for the given account number.
/// </summary>
/// <param name="_custAccount">The customer account number.</param>
/// <returns>The customer name, or an empty string if not found.</returns>
public static Name getCustomerName(CustAccount _custAccount)
{
    CustTable custTable;

    if (_custAccount == '')
    {
        return '';
    }

    select firstOnly Name from custTable
        where custTable.AccountNum == _custAccount;

    if (!custTable.RecId)
    {
        return '';
    }

    return custTable.Name;
}

/// <summary>
/// Checks whether the given customer account exists.
/// </summary>
/// <param name="_custAccount">The customer account number.</param>
/// <returns>True if the customer record exists; otherwise false.</returns>
public static boolean customerExists(CustAccount _custAccount)
{
    CustTable custTable = CustTable::find(_custAccount);

    return custTable.RecId != 0;
}
